const CONVERSATIONS=[{id:"conv_cafe",c:"social",emoji:"\u2615",title:"Kafe Sipari\u015Fi",level:"easy",cefr:"A1",turns:[{bot:["Welcome to Sunrise Caf\xE9! What can I get for you today?","Hi there! Ready to order?","Good morning! What would you like?"],tr:["Sunrise Caf\xE9'ye ho\u015F geldiniz! Bug\xFCn ne al\u0131rd\u0131n\u0131z?","Merhaba! Sipari\u015F vermeye haz\u0131r m\u0131s\u0131n\u0131z?","G\xFCnayd\u0131n! Ne almak isterdiniz?"]},{userHint:"B\xFCy\xFCk boy cappuccino ve \xE7ikolatal\u0131 kek isteyin",keywords:["large","cappuccino","chocolate","cake","please"],expected:"I'd like a large cappuccino and a slice of chocolate cake, please."},{bot:["Sure! Is that to have here or to take away?","Great choice! Eat in or take away?","Coming right up! For here or to go?"],tr:["Tabii! Burada m\u0131 i\xE7eceksiniz, yoksa g\xF6t\xFCrecek misiniz?","Harika se\xE7im! \u0130\xE7eride mi, d\u0131\u015Far\u0131ya g\xF6t\xFCr\xFClecek mi?","Hemen haz\u0131rlayal\u0131m! Burada m\u0131 yoksa g\xF6t\xFCr\xFClecek mi?"]},{userHint:"Burada i\xE7ece\u011Finizi s\xF6yleyin ve fiyat\u0131 sorun",keywords:["here","how much","cost","price"],expected:"To have here, please. How much is that?"},{bot:["That comes to \xA36.50. Cash or card?","That'll be \xA36.50. How would you like to pay?","Six fifty, please. Cash or card?"],tr:["Toplam 6,50 \xA3. Nakit mi kart m\u0131?","Toplam 6,50 \xA3. Nas\u0131l \xF6demek istersiniz?","Alt\u0131 elli l\xFCtfen. Nakit mi kart m\u0131?"]},{userHint:"Kartla \xF6deyece\u011Finizi s\xF6yleyin",keywords:["card","pay","by card"],expected:"I'll pay by card, please."}]},{id:"conv_directions",c:"travel",emoji:"\u{1F5FA}\uFE0F",title:"Yol Tarifi",level:"easy",cefr:"A1",turns:[{bot:["Hello! You look a bit lost \u2014 can I help?","Hi! Are you looking for somewhere?","Excuse me, can I help you find something?"],tr:["Merhaba! Biraz kaybolmu\u015F gibi g\xF6r\xFCn\xFCyorsunuz \u2014 yard\u0131mc\u0131 olabilir miyim?","Selam! Bir yer mi ar\u0131yorsunuz?","Affedersiniz, bir \u015Fey araman\u0131za yard\u0131mc\u0131 olabilir miyim?"]},{userHint:"\u015Eehir m\xFCzesinin nerede oldu\u011Funu sorun",keywords:["city museum","where","get to","directions"],expected:"Yes, please. Can you tell me how to get to the city museum?"},{bot:["Of course! Go straight ahead and turn left at the traffic lights.","Sure! Walk along this road and turn left at the lights.","No problem! Take this road and turn left at the junction."],tr:["Tabii! D\xFCz gidin ve trafik \u0131\u015F\u0131klar\u0131nda sola d\xF6n\xFCn.","Elbette! Bu yolda devam edin ve \u0131\u015F\u0131klarda sola d\xF6n\xFCn.","Sorun de\u011Fil! Bu yolda gidin ve kav\u015Fakta sola d\xF6n\xFCn."]},{userHint:"Y\xFCr\xFCyerek ne kadar s\xFCrece\u011Fini sorun",keywords:["how long","walk","minutes","far"],expected:"Thank you. How long does it take to walk there?"},{bot:["About ten minutes on foot.","It's around ten minutes walking.","Not long at all \u2014 just ten minutes or so."],tr:["Y\xFCr\xFCyerek yakla\u015F\u0131k on dakika.","Y\xFCr\xFCy\xFC\u015Fle on dakika kadar.","\xC7ok uzun de\u011Fil \u2014 on dakika falan."]},{userHint:"Te\u015Fekk\xFCr edin",keywords:["thank","thanks","helpful","appreciate"],expected:"That's great, thank you so much!"}]},{id:"conv_return",c:"social",emoji:"\u{1F6CD}\uFE0F",title:"Ma\u011Fazada \u0130ade",level:"easy",cefr:"A2",turns:[{bot:["Hello, how can I help you today?","Good morning! What can I do for you?","Hi there! What brings you in?"],tr:["Merhaba, bug\xFCn size nas\u0131l yard\u0131mc\u0131 olabilirim?","G\xFCnayd\u0131n! Nas\u0131l yard\u0131mc\u0131 olabilirim?","Merhaba! Ne yapabilirim sizin i\xE7in?"]},{userHint:"Ge\xE7en hafta ald\u0131\u011F\u0131n\u0131z g\xF6mle\u011Fi iade etmek istedi\u011Finizi s\xF6yleyin",keywords:["return","shirt","bought","last week","receipt"],expected:"I'd like to return this shirt I bought last week. I have the receipt."},{bot:["Of course. What seems to be the problem with it?","No problem. What's the reason for the return?","Sure. Is there an issue with the item?"],tr:["Tabii ki. Sorun nedir?","Sorun de\u011Fil. \u0130ade sebebiniz nedir?","Elbette. \xDCr\xFCnde bir sorun mu var?"]},{userHint:"Yanl\u0131\u015F beden oldu\u011Funu s\xF6yleyin",keywords:["wrong size","too small","size","exchange"],expected:"It's the wrong size \u2014 it's too small for me."},{bot:["No problem. Would you like to exchange it or get a refund?","We can swap it for the right size or give you a full refund.","Do you want to exchange it or would you prefer your money back?"],tr:["Sorun de\u011Fil. De\u011Fi\u015Fim mi yapmak istersiniz yoksa para iadesi mi?","Do\u011Fru bedenle de\u011Fi\u015Ftirebilir ya da tam iade yapabiliriz.","De\u011Fi\u015Fim mi yoksa para iadesi mi tercih edersiniz?"]},{userHint:"Do\u011Fru beden i\xE7in de\u011Fi\u015Ftirmek istedi\u011Finizi s\xF6yleyin",keywords:["exchange","medium","size","please"],expected:"I'd like to exchange it for a medium size, please."}]},{id:"conv_airport",c:"travel",emoji:"\u2708\uFE0F",title:"Havaliman\u0131 Check-in",level:"easy",cefr:"A2",turns:[{bot:["Good morning. May I have your passport and booking reference, please?","Hello! Passport and booking confirmation, please.","Welcome. Could I see your travel documents?"],tr:["G\xFCnayd\u0131n. Pasaportunuzu ve rezervasyon kodunuzu alabilir miyim?","Merhaba! Pasaport ve rezervasyon belgesi l\xFCtfen.","Ho\u015F geldiniz. Seyahat belgelerinizi g\xF6rebilir miyim?"]},{userHint:"Pasaportunuzu verin ve pencere kenar\u0131 koltuk isteyin",keywords:["here","passport","window seat","prefer"],expected:"Here's my passport. Could I have a window seat if possible?"},{bot:["Of course! Seat 12A is available \u2014 that's a window seat. How many bags are you checking in?","You're in luck \u2014 12A is free! How many bags to check?","Window seat 12A is available. How many bags today?"],tr:["Tabii! 12A koltu\u011Fu m\xFCsait \u2014 bu bir pencere kenar\u0131. Ka\xE7 bagaj vereceksiniz?","\u015Eans\u0131n\u0131z var \u2014 12A bo\u015F! Ka\xE7 valiz vereceksiniz?","12A pencere kenar\u0131 m\xFCsait. Bug\xFCn ka\xE7 bagaj var?"]},{userHint:"Bir valiz verece\u011Finizi ve el bagaj\u0131n\u0131z\u0131n oldu\u011Funu s\xF6yleyin",keywords:["one suitcase","check","hand luggage","cabin bag"],expected:"I have one suitcase to check in and one hand luggage."},{bot:["Your bag is 18kg \u2014 within the limit. Here's your boarding pass. Gate 14, boarding at 09:30.","18 kilos, all fine! Boarding pass for you. Please go to gate 14, boarding at half nine.","18kg, that's fine. Your boarding pass is ready \u2014 gate 14, boarding 09:30."],tr:["Valiziniz 18 kg \u2014 limit dahilinde. Bini\u015F kart\u0131n\u0131z haz\u0131r. 14 numaral\u0131 kap\u0131, bini\u015F 09:30.","18 kilo, tamam! Bini\u015F kart\u0131n\u0131z. 14. kap\u0131ya gidin, bini\u015F saat 09:30.","18 kg, sorun de\u011Fil. Bini\u015F kart\u0131n\u0131z haz\u0131r \u2014 kap\u0131 14, bini\u015F 09:30."]},{userHint:"Te\u015Fekk\xFCr edin ve 14. kap\u0131n\u0131n nerede oldu\u011Funu sorun",keywords:["thank","where","gate","terminal","find"],expected:"Thank you! Could you tell me where gate 14 is?"}]},{id:"conv_hotel",c:"travel",emoji:"\u{1F3E8}",title:"Otel Check-in",level:"easy",cefr:"A2",turns:[{bot:["Good evening! Welcome. Do you have a reservation?","Hello, welcome to the hotel! Are you checking in?","Good evening! How can I help you?"],tr:["\u0130yi ak\u015Famlar! Ho\u015F geldiniz. Rezervasyonunuz var m\u0131?","Merhaba, otele ho\u015F geldiniz! Check-in mi yapacaks\u0131n\u0131z?","\u0130yi ak\u015Famlar! Nas\u0131l yard\u0131mc\u0131 olabilirim?"]},{userHint:"Ad\u0131n\u0131za rezervasyon yapt\u0131rd\u0131\u011F\u0131n\u0131z\u0131 s\xF6yleyin",keywords:["reservation","booking","name","yes"],expected:"Yes, I have a reservation. It should be under my name."},{bot:["Of course. Could I have your full name, please?","What name is the booking under?","And the name on the reservation?"],tr:["Tabii ki. Tam ad\u0131n\u0131z\u0131 alabilir miyim?","Rezervasyon kimin ad\u0131na?","Rezervasyondaki isim nedir?"]},{userHint:"Ad\u0131n\u0131z\u0131 s\xF6yleyin ve iki gecelik \xE7ift ki\u015Filik oda oldu\u011Funu belirtin",keywords:["name","two nights","double room","nights"],expected:"It's [name]. It should be a double room for two nights."},{bot:["Perfect, I have it here. Could I see your passport for a moment?","Found it! May I briefly see your passport?","Here we are. I just need your passport for check-in."],tr:["M\xFCkemmel, kay\u0131tlar\u0131m\u0131zda var. Pasaportunuzu bir an i\xE7in g\xF6rebilir miyim?","Buldum! Pasaportunuzu k\u0131saca g\xF6rebilir miyim?","\u0130\u015Fte burada. Check-in i\xE7in pasaportunuza ihtiyac\u0131m var."]},{userHint:"Pasaportunuzu verin ve erken check-in m\xFCmk\xFCn m\xFC diye sorun",keywords:["here","passport","early check-in","possible","ready"],expected:"Here it is. Is early check-in possible, by any chance?"}]},{id:"conv_doctor",c:"medical",emoji:"\u{1FA7A}",title:"Doktor Muayenesi",level:"medium",cefr:"B1",turns:[{bot:["Good morning. Please take a seat. What seems to be the problem?","Hello! Come in. What brings you in today?","Good morning. What's been troubling you?"],tr:["G\xFCnayd\u0131n. L\xFCtfen oturun. Sorun nedir?","Merhaba! Buyurun. Bug\xFCn sizi getiren nedir?","G\xFCnayd\u0131n. Sizi rahats\u0131z eden ne?"]},{userHint:"\xDC\xE7 g\xFCnd\xFCr bo\u011Faz a\u011Fr\u0131s\u0131 ve ate\u015Finiz oldu\u011Funu s\xF6yleyin",keywords:["sore throat","fever","three days","temperature","pain"],expected:"I've had a sore throat and a fever for about three days now."},{bot:["I see. Let me take your temperature... 38.5 \u2014 slightly elevated. Are you taking any medication?","38.5 \u2014 a bit high. Have you taken anything for it?","That's a slight fever. Are you on any medicine currently?"],tr:["Anl\u0131yorum. Ate\u015Finizi \xF6l\xE7eyim... 38.5 \u2014 biraz y\xFCksek. Herhangi bir ila\xE7 kullan\u0131yor musunuz?","38.5 \u2014 biraz y\xFCksek. Bir \u015Fey ald\u0131n\u0131z m\u0131?","Hafif ate\u015F var. \u015Eu an herhangi bir ila\xE7 kullan\u0131yor musunuz?"]},{userHint:"Parasetamol ald\u0131\u011F\u0131n\u0131z\u0131 ama i\u015Fe yaramad\u0131\u011F\u0131n\u0131 s\xF6yleyin",keywords:["paracetamol","taking","not helping","still","temperature"],expected:"I've been taking paracetamol, but it's not really helping."},{bot:["I'll prescribe antibiotics. One tablet twice a day with food. Come back in five days if there's no improvement.","I'm putting you on a course of antibiotics \u2014 twice daily with meals. Return in five days if needed.","Antibiotics should clear this up. Twice a day with food, five-day course. Come back if it persists."],tr:["Antibiyotik yaz\u0131yorum. G\xFCnde iki kez yemekle birlikte bir tablet. Be\u015F g\xFCn i\xE7inde iyile\u015Fme olmazsa gelin.","Antibiyotik k\xFCr\xFC ba\u015Flat\u0131yorum \u2014 g\xFCnde iki kez yemekle. Gerekirse be\u015F g\xFCn sonra gelin.","Antibiyotik sorunu \xE7\xF6zecektir. G\xFCnde iki kez yemekle, be\u015F g\xFCnl\xFCk k\xFCr. \u0130yile\u015Fmezse gelin."]},{userHint:"Te\u015Fekk\xFCr edin ve yan etkiler olup olmad\u0131\u011F\u0131n\u0131 sorun",keywords:["thank","side effects","anything","worry","know"],expected:"Thank you, doctor. Are there any side effects I should be aware of?"}]},{id:"conv_flat",c:"social",emoji:"\u{1F3E1}",title:"Kiral\u0131k Ev G\xF6r\xFC\u015Fmesi",level:"medium",cefr:"B1",turns:[{bot:["Hi! You must be here about the flat. Come in and have a look around!","Hello! Glad you could make it. Shall we start with a tour?","Good afternoon! You're here about the two-bedroom flat, right? Let me show you around."],tr:["Merhaba! Daire i\xE7in geldiniz, de\u011Fil mi? Buyurun, bir bak\u0131n!","Selam! Geldi\u011Finize sevindim. Turu ba\u015Flatal\u0131m m\u0131?","\u0130yi \xF6\u011Fleden sonralar! \u0130ki odal\u0131 daire i\xE7in geldiniz, de\u011Fil mi? Gezdireyim."]},{userHint:"Evet oldu\u011Funuzu onaylay\u0131n ve ilan\u0131 online g\xF6rd\xFC\u011F\xFCn\xFCz\xFC s\xF6yleyin",keywords:["yes","online","listing","saw","interested"],expected:"Yes, that's right. I saw the listing online and I'm very interested."},{bot:["Great! It's two bedrooms, fully furnished, \xA31,200 per month. Bills are not included.","It's a two-bed, furnished flat. Rent is \xA31,200 monthly \u2014 bills extra.","Two bedrooms, fully furnished. \xA31,200 a month, not including utilities."],tr:["Harika! \u0130ki yatak odal\u0131, tam e\u015Fyal\u0131, ayl\u0131k 1.200 \xA3. Faturalar dahil de\u011Fil.","\u0130ki odal\u0131, e\u015Fyal\u0131 daire. Kira ayl\u0131k 1.200 \xA3 \u2014 faturalar ayr\u0131.","\u0130ki yatak odal\u0131, tam e\u015Fyal\u0131. Ayl\u0131k 1.200 \xA3, faturalar hari\xE7."]},{userHint:"Yak\u0131nlarda park olup olmad\u0131\u011F\u0131n\u0131 ve evcil hayvan politikas\u0131n\u0131 sorun",keywords:["park","near","pets","allowed","policy"],expected:"Is there a park nearby? Also, are pets allowed in the flat?"},{bot:["There's a park five minutes away. Pets are allowed \u2014 small ones \u2014 with a small additional deposit.","Yes, there's a lovely park nearby! Small pets are fine, though we ask for a small extra deposit.","The park is a short walk away. We do allow pets with an additional deposit."],tr:["Be\u015F dakika y\xFCr\xFCme mesafesinde bir park var. Evcil hayvanlara izin var \u2014 k\xFC\xE7\xFCk olanlara \u2014 ek depozito ile.","Evet, yak\u0131nda g\xFCzel bir park var! K\xFC\xE7\xFCk evcil hayvanlara izin veriyoruz, ek depozito ile.","Park k\u0131sa y\xFCr\xFCme mesafesinde. Ek depozito ile evcil hayvana izin veriyoruz."]},{userHint:"Ne zaman ta\u015F\u0131n\u0131labilece\u011Fini sorun ve be\u011Fendi\u011Finizi belirtin",keywords:["when","move in","available","love","wonderful"],expected:"The flat is wonderful. When would it be available to move in?"}]},{id:"conv_university",c:"business",emoji:"\u{1F393}",title:"\xDCniversite Kay\u0131t G\xF6r\xFC\u015Fmesi",level:"medium",cefr:"B2",turns:[{bot:["Hello! I'm the admissions officer. I see you've applied for Business Management \u2014 is that right?","Welcome! Let's go through your Business Management application together.","Good morning! You're applying for our Business Management programme. Let's get started."],tr:["Merhaba! Kay\u0131t g\xF6revlisiyim. \u0130\u015Fletme Y\xF6netimi i\xE7in ba\u015Fvurdu\u011Funuzu g\xF6r\xFCyorum \u2014 do\u011Fru mu?","Ho\u015F geldiniz! \u0130\u015Fletme Y\xF6netimi ba\u015Fvurunuzu birlikte inceleyelim.","G\xFCnayd\u0131n! \u0130\u015Fletme Y\xF6netimi program\u0131m\u0131za ba\u015Fvuruyorsunuz. Ba\u015Flayal\u0131m."]},{userHint:"Evet oldu\u011Funu onaylay\u0131n ve heyecanl\u0131 oldu\u011Funuzu belirtin",keywords:["yes","correct","excited","looking forward","application"],expected:"Yes, that's correct. I'm very excited about this opportunity."},{bot:["Wonderful. Your academic record looks strong. Why did you choose Business Management specifically?","Your grades are solid. What drew you to Business Management?","Your application is impressive. Why this programme in particular?"],tr:["Harika. Akademik kayd\u0131n\u0131z g\xFC\xE7l\xFC g\xF6r\xFCn\xFCyor. Neden \xF6zellikle \u0130\u015Fletme Y\xF6netimi?","Notlar\u0131n\u0131z sa\u011Flam. Sizi \u0130\u015Fletme Y\xF6netimi'ne \xE7eken ne oldu?","Ba\u015Fvurunuz etkileyici. \xD6zellikle bu program\u0131 neden se\xE7tiniz?"]},{userHint:"\u0130\u015Fletmeye olan ilginizden ve analitik becerilerinizden bahsedin",keywords:["passionate","business","analytical","skills","career","interest"],expected:"I'm passionate about business and I believe my analytical skills make it a great fit for my career goals."},{bot:["Great answer. The programme includes a work placement in year two. Do you have any relevant work experience?","Excellent! We have a placement year in the programme. Any work experience so far?","Fantastic. Our course has a work placement component. Do you have any experience to mention?"],tr:["Harika cevap. Program ikinci y\u0131lda staj i\xE7eriyor. \u0130lgili i\u015F deneyiminiz var m\u0131?","M\xFCkemmel! Programda staj y\u0131l\u0131 var. \u015Eimdiye kadar i\u015F deneyiminiz oldu mu?","Fantastik. Kursumuzun staj bile\u015Feni var. Bahsedebilece\u011Finiz bir deneyim var m\u0131?"]},{userHint:"Part-time \xE7al\u0131\u015Ft\u0131\u011F\u0131n\u0131z\u0131 ve deneyimin de\u011Ferli oldu\u011Funu s\xF6yleyin",keywords:["part-time","work","experience","valuable","learned"],expected:"I've been working part-time in a local business, which has been really valuable experience."}]},{id:"conv_lost",c:"emergency",emoji:"\u{1F392}",title:"Kay\u0131p E\u015Fya Bildirimi",level:"medium",cefr:"B1",turns:[{bot:["Lost property office, can I help you?","Hello, you've reached the lost property office. How can I assist?","Lost and found \u2014 how can I help?"],tr:["Kay\u0131p e\u015Fya ofisi, nas\u0131l yard\u0131mc\u0131 olabilirim?","Merhaba, kay\u0131p e\u015Fya ofisine ula\u015Ft\u0131n\u0131z. Nas\u0131l yard\u0131mc\u0131 olabilirim?","Kay\u0131p e\u015Fya \u2014 nas\u0131l yard\u0131mc\u0131 olabilirim?"]},{userHint:"Trende \xE7antan\u0131z\u0131 unuttu\u011Funuzu ve i\xE7inde \xF6nemli \u015Feyler oldu\u011Funu s\xF6yleyin",keywords:["bag","left","train","important","forgot"],expected:"I left my bag on the train earlier today. It has some important things inside."},{bot:["I'm sorry to hear that. Can you describe the bag and tell me which line?","Oh no! What does it look like, and which line were you on?","Let's try to find it. Can you describe the bag and the route you took?"],tr:["\xC7ok \xFCzg\xFCn\xFCm. \xC7antay\u0131 tarif edebilir misiniz ve hangi hattayd\u0131n\u0131z?","Vay be! Nas\u0131l bir \u015Fey ve hangi hattayd\u0131n\u0131z?","Bulmaya \xE7al\u0131\u015Fal\u0131m. \xC7antay\u0131 tarif edebilir ve rotan\u0131z\u0131 s\xF6yleyebilir misiniz?"]},{userHint:"Siyah s\u0131rt \xE7antas\u0131 oldu\u011Funu ve Victoria hatt\u0131nda b\u0131rakt\u0131\u011F\u0131n\u0131z\u0131 s\xF6yleyin",keywords:["black","backpack","Victoria line","afternoon","around"],expected:"It's a black backpack. I left it on the Victoria line around 3 PM this afternoon."},{bot:["We do have a black backpack handed in this afternoon. Can you tell me what's inside to confirm it's yours?","Actually, a black backpack was handed in! Can you confirm the contents?","There's a black backpack here. What are the contents so we can verify it's yours?"],tr:["Bu \xF6\u011Fleden sonra teslim edilmi\u015F bir siyah s\u0131rt \xE7antam\u0131z var. \u0130\xE7indekiler neler?","Asl\u0131nda, bir siyah s\u0131rt \xE7antas\u0131 teslim edildi! \u0130\xE7indekiler neler?","Burada siyah bir s\u0131rt \xE7antas\u0131 var. Sizin oldu\u011Funu do\u011Frulamak i\xE7in i\xE7indekiler neler?"]},{userHint:"Laptop, c\xFCzdan ve mavi defterin i\xE7inde oldu\u011Funu s\xF6yleyin",keywords:["laptop","wallet","notebook","blue","inside"],expected:"There's a laptop, a wallet, and a blue notebook inside."}]},{id:"conv_visa",c:"travel",emoji:"\u{1F6C2}",title:"Vize M\xFClakat\u0131",level:"medium",cefr:"B2",turns:[{bot:["Good morning. Please state your full name and the purpose of your visit.","Hello. Could you tell me your name and why you wish to visit the UK?","Good morning. Please introduce yourself and explain the reason for your application."],tr:["G\xFCnayd\u0131n. L\xFCtfen tam ad\u0131n\u0131z\u0131 ve ziyaret amac\u0131n\u0131z\u0131 belirtin.","Merhaba. Ad\u0131n\u0131z\u0131 ve neden \u0130ngiltere'yi ziyaret etmek istedi\u011Finizi s\xF6yler misiniz?","G\xFCnayd\u0131n. L\xFCtfen kendinizi tan\u0131t\u0131n ve ba\u015Fvuru nedeninizi a\xE7\u0131klay\u0131n."]},{userHint:"Ad\u0131n\u0131z\u0131 s\xF6yleyin ve i\u015F konferans\u0131 i\xE7in gitti\u011Finizi belirtin",keywords:["name","business","conference","attend","company","representing"],expected:"My name is [name]. I'm attending a three-day business conference representing my company."},{bot:["How long do you intend to stay, and where will you be staying?","And the duration of your stay? Do you have accommodation arranged?","What is the planned length of your visit, and do you have a place to stay?"],tr:["Ne kadar kalmay\u0131 d\xFC\u015F\xFCn\xFCyorsunuz ve nerede kalacaks\u0131n\u0131z?","Kal\u0131\u015F s\xFCreniz? Konaklama ayarlad\u0131n\u0131z m\u0131?","Ziyaretinizin planlanan s\xFCresi nedir ve kalacak yeriniz var m\u0131?"]},{userHint:"5 g\xFCn kalaca\u011F\u0131n\u0131z\u0131 ve otel rezervasyonunuz oldu\u011Funu s\xF6yleyin",keywords:["five days","hotel","booked","accommodation","central"],expected:"I plan to stay for five days. I have a hotel booked in central London."},{bot:["What guarantees your return? Employment, family, financial commitments?","Do you have ties to your home country \u2014 work, family, property?","How can you demonstrate your intention to return home after your visit?"],tr:["D\xF6n\xFC\u015F\xFCn\xFCz\xFC ne garanti ediyor? \u0130\u015F, aile, mali y\xFCk\xFCml\xFCl\xFCkler?","\xDClkenizle ba\u011Flant\u0131lar\u0131n\u0131z var m\u0131 \u2014 i\u015F, aile, m\xFClk?","Ziyaret sonras\u0131 eve d\xF6nme niyetinizi nas\u0131l kan\u0131tlayabilirsiniz?"]},{userHint:"Sabit i\u015Finiz ve ailenizin orada oldu\u011Funu s\xF6yleyin",keywords:["employed","job","family","home","return","ties"],expected:"I'm employed full-time and my family is at home. I have every reason to return."}]},{id:"scen_v3_1",c:"business",emoji:"\u{1F4BC}",title:"Yat\u0131r\u0131mc\u0131 Sunumu (Pitch)",level:"hard",cefr:"C1",turns:[{bot:["Welcome. We've reviewed your pitch deck. What is your primary competitive advantage?","Glad to have you here. Your deck looks promising \u2014 what makes you stand out most?","Thanks for coming. We have some concerns. What exactly is your competitive edge?"],tr:["Ho\u015F geldiniz. Sunum dosyan\u0131z\u0131 inceledik. Temel rekabet avantaj\u0131n\u0131z nedir?","Sizi burada g\xF6rmek g\xFCzel. Sunumunuz umut verici \u2014 sizi en \xE7ok \xF6ne \xE7\u0131karan nedir?","Geldi\u011Finiz i\xE7in te\u015Fekk\xFCrler ama baz\u0131 endi\u015Felerimiz var. Rekabet avantaj\u0131n\u0131z nedir?"]},{userHint:"Yapay zeka tabanl\u0131 algoritman\u0131zdan ve pazar pay\u0131n\u0131zdan bahsedin",keywords:["unique","ai","algorithm","market","share","advantage"],expected:"Our unique AI algorithm and rapidly growing market share are our biggest advantages."},{bot:["Interesting. How do you plan to scale internationally within the next year?","That sounds solid. Do you have a clear strategy for international expansion?","I see \u2014 scaling globally is difficult. How do you intend to handle international growth?"],tr:["\u0130lgin\xE7. \xD6n\xFCm\xFCzdeki y\u0131l i\xE7inde bunu uluslararas\u0131 d\xFCzeyde nas\u0131l \xF6l\xE7eklendirmeyi planl\u0131yorsunuz?","Kula\u011Fa sa\u011Flam geliyor. Uluslararas\u0131 \xF6l\xE7eklendirme i\xE7in net bir stratejiniz var m\u0131?","Anl\u0131yorum ama k\xFCresel \xF6l\xE7eklendirme zordur. Uluslararas\u0131 b\xFCy\xFCmeyi nas\u0131l y\xF6netmeyi d\xFC\u015F\xFCn\xFCyorsunuz?"]},{userHint:"Yerel ortakl\u0131klar kuraca\u011F\u0131n\u0131z\u0131 ve dijital pazarlamaya odaklanaca\u011F\u0131n\u0131z\u0131 s\xF6yleyin",keywords:["local","partnerships","digital","marketing","global","focus"],expected:"We plan to establish local partnerships and focus heavily on digital marketing for global growth."}]},{id:"conv_salary",c:"business",emoji:"\u{1F4B0}",title:"Maa\u015F Pazarl\u0131\u011F\u0131",level:"hard",cefr:"C1",turns:[{bot:["Hello. I understand you wanted to discuss your compensation. What's on your mind?","Hi, glad you brought this up. Talk me through your thinking on salary.","Good to meet. You've requested a salary discussion \u2014 let's hear your case."],tr:["Merhaba. \xDCcret konusunu g\xF6r\xFC\u015Fmek istedi\u011Finizi anl\u0131yorum. Ne d\xFC\u015F\xFCn\xFCyorsunuz?","Selam, bunu g\xFCndeme getirdi\u011Finize sevindim. Maa\u015F konusundaki d\xFC\u015F\xFCncelerinizi anlat\u0131n.","Tan\u0131\u015Fmak g\xFCzel. Maa\u015F g\xF6r\xFC\u015Fmesi talep ettiniz \u2014 arg\xFCmanlar\u0131n\u0131z\u0131 dinleyelim."]},{userHint:"Performans\u0131n\u0131z\u0131 ve piyasa ara\u015Ft\u0131rman\u0131z\u0131 sunun, belirli bir art\u0131\u015F talep edin",keywords:["performance","market","research","increase","raise","deserve"],expected:"Based on my performance this year and market research, I'd like to discuss a 15% salary increase."},{bot:["That's a significant ask. Walk me through the market data you've looked at.","15% is bold. What market research supports that figure?","Interesting. Can you back that number up with data?"],tr:["Bu ciddi bir talep. Bakt\u0131\u011F\u0131n\u0131z piyasa verilerini anlat\u0131n.","15% cesur bir talep. Bu rakam\u0131 hangi piyasa ara\u015Ft\u0131rmas\u0131 destekliyor?","\u0130lgin\xE7. Bu rakam\u0131 verilerle destekleyebilir misiniz?"]},{userHint:"Sekt\xF6r verilerini ve katk\u0131lar\u0131n\u0131z\u0131 a\xE7\u0131klay\u0131n",keywords:["industry","data","contribution","revenue","results","evidence"],expected:"Industry benchmarks show my role averages 12\u201318% higher. I also drove a 22% revenue increase last quarter."},{bot:["Those are strong numbers. I can approve 10% immediately, with a review in six months for the remainder. Does that work?","That's compelling. I can offer 10% now with a structured review for the rest in Q3. What do you think?","Solid case. I'm able to offer 10% now and commit to revisiting the full amount in six months."],tr:["Bunlar g\xFC\xE7l\xFC rakamlar. \u015Eimdi 10% onaylayabilirim ve alt\u0131 ay i\xE7inde geri kalan\u0131 i\xE7in de\u011Ferlendirme yapar\u0131z. Uygun mudur?","\u0130kna edici. \u015Eimdi 10% teklif edebilir, geri kalan\u0131 i\xE7in Q3'te yap\u0131land\u0131r\u0131lm\u0131\u015F bir de\u011Ferlendirme yapar\u0131m. Ne d\xFC\u015F\xFCn\xFCrs\xFCn\xFCz?","Sa\u011Flam arg\xFCman. \u015Eimdi 10% teklif edebilir, tam tutara alt\u0131 ay i\xE7inde tekrar bakaca\u011F\u0131m\u0131 taahh\xFCt edebilirim."]},{userHint:"Teklife yan\u0131t verin ve yap\u0131land\u0131r\u0131lm\u0131\u015F g\xF6zden ge\xE7irmeyi netle\u015Ftirin",keywords:["appreciate","accept","confirm","review","timeline","written"],expected:"I appreciate that. I'd accept on the condition that the six-month review is confirmed in writing."}]},{id:"conv_interview",c:"business",emoji:"\u{1F91D}",title:"\u0130\u015F G\xF6r\xFC\u015Fmesi",level:"hard",cefr:"C1",turns:[{bot:["Good morning. Please take a seat. Tell me a little about yourself and your professional background.","Welcome. Could you briefly introduce yourself and outline your experience?","Good morning. Let's start with a brief introduction \u2014 who are you and what's your background?"],tr:["G\xFCnayd\u0131n. L\xFCtfen oturun. Kendinizden ve profesyonel ge\xE7mi\u015Finizden biraz bahsedin.","Ho\u015F geldiniz. Kendinizi k\u0131saca tan\u0131tabilir ve deneyiminizi \xF6zetleyebilir misiniz?","G\xFCnayd\u0131n. K\u0131sa bir tan\u0131t\u0131mla ba\u015Flayal\u0131m \u2014 kim oldu\u011Funuzu ve ge\xE7mi\u015Finizi anlat\u0131n."]},{userHint:"Deneyiminizi, g\xFC\xE7l\xFC y\xF6nlerinizi ve neden bu pozisyona ba\u015Fvurdu\u011Funuzu anlat\u0131n",keywords:["experience","passionate","role","skills","contribute","background"],expected:"I have five years of experience in marketing and I'm passionate about growth strategy. I applied because this role perfectly matches my skills."},{bot:["Interesting. Can you describe a challenging professional situation and how you resolved it?","Tell me about a time you dealt with a difficult challenge at work and what you learned.","What's the most significant professional challenge you've overcome?"],tr:["\u0130lgin\xE7. Zorlu bir profesyonel durumu ve onu nas\u0131l \xE7\xF6zd\xFC\u011F\xFCn\xFCz\xFC anlatabilir misiniz?","\u0130\u015Fte ya\u015Fad\u0131\u011F\u0131n\u0131z zor bir durumu ve \xF6\u011Frendiklerinizi anlat\u0131n.","A\u015Ft\u0131\u011F\u0131n\u0131z en \xF6nemli profesyonel zorluk neydi?"]},{userHint:"Zor bir projeden, \xE7\xF6z\xFCm\xFCn\xFCzden ve sonucundan bahsedin",keywords:["challenge","team","deadline","solution","result","learned"],expected:"We faced a major deadline crisis on a product launch. I restructured the team's workflow and we delivered two days early."},{bot:["Impressive. Where do you see yourself professionally in five years?","And looking ahead \u2014 what are your five-year career goals?","Great answer. What's your vision for the next five years in this field?"],tr:["Etkileyici. Kendinizi be\u015F y\u0131l sonra profesyonel a\xE7\u0131dan nerede g\xF6r\xFCyorsunuz?","\u0130leriye bakarak \u2014 be\u015F y\u0131ll\u0131k kariyer hedefleriniz neler?","Harika cevap. Bu alanda \xF6n\xFCm\xFCzdeki be\u015F y\u0131l i\xE7in vizyonunuz nedir?"]},{userHint:"Liderlik rol\xFC hedefledi\u011Finizi ve uzun vadeli b\xFCy\xFCmek istedi\u011Finizi belirtin",keywords:["leadership","senior","grow","long-term","develop","vision"],expected:"I aim to develop into a senior leadership role and grow with the company long-term."}]},{id:"conv_performance",c:"business",emoji:"\u{1F4CA}",title:"Performans De\u011Ferlendirmesi",level:"hard",cefr:"C1",turns:[{bot:["Thanks for coming in. Overall it's been a strong quarter \u2014 what highlights would you like to mention first?","Let's begin the review. It's been productive. What achievements are you most proud of?","Before I share feedback, what do you feel went particularly well this quarter?"],tr:["Geldi\u011Finiz i\xE7in te\u015Fekk\xFCrler. Genel olarak g\xFC\xE7l\xFC bir \xE7eyrek oldu \u2014 \xF6nce \xF6ne \xE7\u0131karmak istedi\u011Finiz noktalar var m\u0131?","De\u011Ferlendirmeye ba\u015Flayal\u0131m. Verimli ge\xE7ti. En \xE7ok neyle gurur duyuyorsunuz?","Geri bildirim vermeden \xF6nce \u2014 bu \xE7eyrekte \xF6zellikle neyin iyi gitti\u011Fini d\xFC\u015F\xFCn\xFCyorsunuz?"]},{userHint:"Projeyi zaman\u0131nda bitirdi\u011Finizden ve m\xFC\u015Fteri memnuniyetini art\u0131rd\u0131\u011F\u0131n\u0131zdan bahsedin",keywords:["delivered","on time","client satisfaction","improved","exceeded","target"],expected:"I delivered the Henderson project on time and client satisfaction scores improved by 18% this quarter."},{bot:["Excellent results. One development area: cross-team communication could be stronger. Your thoughts?","Great work. On development \u2014 interdepartmental communication has come up in feedback. How do you see it?","Strong outcomes. One point to develop: wider team communication. What's your perspective?"],tr:["M\xFCkemmel sonu\xE7lar. Bir geli\u015Fim alan\u0131: \xE7apraz tak\u0131m ileti\u015Fimi g\xFC\xE7lendirilebilir. D\xFC\u015F\xFCnceleriniz?","Harika i\u015F. Geli\u015Fim a\xE7\u0131s\u0131ndan \u2014 departmanlar aras\u0131 ileti\u015Fim geri bildirimde \xF6ne \xE7\u0131kt\u0131. Siz nas\u0131l g\xF6r\xFCyorsunuz?","G\xFC\xE7l\xFC sonu\xE7lar. Geli\u015Ftirme noktas\u0131: daha geni\u015F ekip ileti\u015Fimi. Bak\u0131\u015F a\xE7\u0131n\u0131z nedir?"]},{userHint:"Kabul edin ve nas\u0131l geli\u015Ftirece\u011Finize dair plan\u0131n\u0131z\u0131 a\xE7\u0131klay\u0131n",keywords:["acknowledge","improve","plan","weekly","meetings","aware","briefings"],expected:"I acknowledge that. I plan to introduce weekly cross-team briefings to improve communication going forward."},{bot:["Proactive thinking. We're also considering you for team lead next quarter. Are you ready for that?","Good initiative. There's also news: we'd like to put you forward for team lead from Q2. How do you feel?","Sounds constructive. On a positive note, you're being considered for team lead. Does that interest you?"],tr:["Proaktif d\xFC\u015F\xFCnce. Ayr\u0131ca sizi gelecek \xE7eyrekte tak\u0131m liderli\u011Fi i\xE7in d\xFC\u015F\xFCn\xFCyoruz. Haz\u0131r m\u0131s\u0131n\u0131z?","\u0130yi inisiyatif. Ayr\u0131ca bir haber: sizi Q2'den itibaren tak\u0131m liderli\u011Fine \xF6nermeyi d\xFC\u015F\xFCn\xFCyoruz. Nas\u0131l hissediyorsunuz?","Yap\u0131c\u0131 geliyor. Olumlu bir not olarak, tak\u0131m liderli\u011Fi i\xE7in d\xFC\u015F\xFCn\xFCl\xFCyorsunuz. \u0130lginizi \xE7ekiyor mu?"]},{userHint:"Heyecanl\u0131 oldu\u011Funuzu ve haz\u0131r oldu\u011Funuzu s\xF6yleyin, rol\xFCn kapsam\u0131n\u0131 sorun",keywords:["excited","ready","responsibility","grateful","understand","involves"],expected:"I'm genuinely excited and feel ready for that responsibility. Could you walk me through what the role involves?"}]},{id:"conv_panel",c:"business",emoji:"\u{1F3A4}",title:"Konferans Paneli",level:"hard",cefr:"C2",turns:[{bot:["Welcome to the panel. First question: how will artificial intelligence reshape the workplace over the next decade?","Let's begin. What's your view on AI's impact on employment and professional environments?","Our opening question: what role do you see AI playing in reshaping work over the next ten years?"],tr:["Panele ho\u015F geldiniz. \u0130lk soru: yapay zeka \xF6n\xFCm\xFCzdeki on y\u0131lda i\u015F d\xFCnyas\u0131n\u0131 nas\u0131l yeniden \u015Fekillendirecek?","Ba\u015Flayal\u0131m. Yapay zekan\u0131n istihdam ve profesyonel ortamlar \xFCzerindeki etkisine bak\u0131\u015F a\xE7\u0131n\u0131z nedir?","A\xE7\u0131l\u0131\u015F sorusu: \xF6n\xFCm\xFCzdeki on y\u0131lda yapay zekan\u0131n \xE7al\u0131\u015Fma hayat\u0131n\u0131 \u015Fekillendirmede nas\u0131l bir rol oynayaca\u011F\u0131n\u0131 d\xFC\u015F\xFCn\xFCyorsunuz?"]},{userHint:"AI'n\u0131n i\u015Fleri ortadan kald\u0131rmak yerine d\xF6n\xFC\u015Ft\xFCrece\u011Fini ve yeni rollerin ortaya \xE7\u0131kaca\u011F\u0131n\u0131 savunun",keywords:["transform","replace","new roles","adapt","augment","human"],expected:"AI will primarily transform roles rather than eliminate them. New positions will emerge that require humans to adapt and collaborate with AI systems."},{bot:["A measured view. Are organisations moving fast enough to prepare their workforces for this transition?","Interesting. Do you feel companies are adequately preparing employees for AI-driven change?","Thoughtful. Are businesses keeping pace in terms of workforce preparation for this shift?"],tr:["\xD6l\xE7\xFCl\xFC bir g\xF6r\xFC\u015F. Kurulu\u015Flar i\u015F g\xFC\xE7lerini bu ge\xE7i\u015F i\xE7in yeterince h\u0131zl\u0131 haz\u0131rl\u0131yor mu?","\u0130lgin\xE7. \u015Eirketlerin yapay zeka odakl\u0131 de\u011Fi\u015Fim i\xE7in \xE7al\u0131\u015Fanlar\u0131 yeterince haz\u0131rlad\u0131\u011F\u0131n\u0131 d\xFC\u015F\xFCn\xFCyor musunuz?","D\xFC\u015F\xFCnceli. \u0130\u015Fletmeler bu de\u011Fi\u015Fim i\xE7in i\u015F g\xFCc\xFC haz\u0131rl\u0131\u011F\u0131 a\xE7\u0131s\u0131ndan yeterince h\u0131zl\u0131 m\u0131?"]},{userHint:"\xC7o\u011Fu \u015Firketin yava\u015F oldu\u011Funu ama \xF6nc\xFC \u015Firketlerin iyi \xF6rnekler sergiledi\u011Fini belirtin",keywords:["most","behind","however","leading","companies","reskilling","examples"],expected:"Most organisations are lagging behind, though leading companies are investing heavily in reskilling \u2014 and those examples should be studied and replicated."},{bot:["Final question: what single piece of advice would you give to someone entering the workforce today?","To close \u2014 what's the most important quality for professionals navigating this period of change?","Last question: what's your advice for a young professional beginning their career right now?"],tr:["Son soru: bug\xFCn i\u015F g\xFCc\xFCne giren birine verece\u011Finiz tek tavsiye nedir?","Kapan\u0131\u015F \u2014 bu de\u011Fi\u015Fim d\xF6neminde profesyoneller i\xE7in en \xF6nemli \xF6zellik nedir?","Son soru: kariyerine \u015Fu an ba\u015Flayan gen\xE7 bir profesyonele tavsiyeniz nedir?"]},{userHint:"Adaptasyon ve s\xFCrekli \xF6\u011Frenme yetene\u011Finin teknik becerilerden daha \xF6nemli oldu\u011Funu s\xF6yleyin",keywords:["adaptability","continuous learning","mindset","skills","durable","advantage"],expected:"Cultivate adaptability above all else. Technical skills become outdated quickly, but the ability to learn continuously is a durable competitive advantage."}]}];
